insert into public.adventures(id, week_index, status, publish_date, title, subtitle, content) values
('week1-day1-temple', 0, 'draft', null, 'Temple of the Sun', 'The Eclipse Trial', '{"id":"week1-day1-temple","weekIndex":0,"status":"draft","publishDate":null,"title":"Temple of the Sun","subtitle":"The Eclipse Trial","synopsis":"Recover the Sunstone before a total eclipse seals the temple for another century.","estimatedMinutes":"6–8 minutes","art":{"key":"temple","background":"backplates/temple.webp","accent":"#f2b544","accent2":"#e76f51","ink":"#1d2931","paper":"#fff8e7","atmosphere":"Sunlit sandstone, deep ravines, carved animal guardians","artifact":"Sunstone","motif":"☀"},"levelOrder":["logic","trivia","rhythm","spatial","finale"],"puzzles":{"trivia":{"type":"trivia","title":"Archive of Glyphs","brief":"Answer all three questions. One wrong tablet opens the floor.","questions":[{"prompt":"Whose tomb did Howard Carter discover largely intact in 1922?","choices":["Ramesses II","Tutankhamun","Cleopatra VII","Akhenaten"],"correct":1,"fact":"Howard Carter discovered Tutankhamun’s tomb in 1922."},{"prompt":"Alongside Ancient Greek and Demotic, which script appears on the Rosetta Stone?","choices":["Cuneiform","Latin","Hieroglyphic","Phoenician"],"correct":2,"fact":"The decree appears in Greek, Demotic, and Egyptian hieroglyphs."},{"prompt":"Which Nile plant was made into a common ancient writing surface?","choices":["Papyrus","Lotus","Flax","Reed grass"],"correct":0,"fact":"Papyrus strips were layered and pressed into writing sheets."}]},"logic":{"type":"logic","title":"Bridge of Idols","brief":"Arrange four temple guardians using every inscription.","tokens":["Sun","Owl","Serpent","Jaguar"],"clues":[{"text":"The Owl is not at either end.","rule":{"kind":"notPosition","token":"Owl","indexes":[0,3]}},{"text":"The Jaguar stands immediately right of the Serpent.","rule":{"kind":"immediatelyBefore","left":"Serpent","right":"Jaguar"}},{"text":"The Sun is somewhere left of the Owl.","rule":{"kind":"before","left":"Sun","right":"Owl"}},{"text":"The Serpent is not first.","rule":{"kind":"notPosition","token":"Serpent","indexes":[0]}}],"solution":["Sun","Owl","Serpent","Jaguar"]},"rhythm":{"type":"rhythm","title":"Bridge of Drums","brief":"Tap when each gold ring reaches the drum to leap the collapsing gaps.","actionLabel":"LEAP","cueLabel":"NOW","beatMap":[2400,4500,6800,9000,11200,13600,15900,18300,20700,23100,25600,28100],"durationMs":30000,"windowMs":360,"maxErrors":3},"spatial":{"type":"spatial","title":"Hall of a Thousand Eyes","brief":"Find the scarab latch in no more than three taps.","clue":"Two sunbeams cross beneath the bird that watches the west wall.","targetLabel":"Scarab latch","target":{"x":286,"y":363,"radius":34},"hints":["Follow the brightest rays.","Look just below the falcon’s eye."],"maxTaps":3},"finale":{"type":"finale","title":"Eclipse Engine","brief":"Recall the trail, find the hidden release, charge the mechanism, and aim the mirror.","question":{"prompt":"Which object translated the temple archive?","choices":["A crown","A stone with repeated scripts","A sundial","A gold mask"],"correct":1,"fact":"The Rosetta Stone repeated one decree in three scripts."},"orderTokens":["Dawn","Noon","Dusk"],"orderSolution":["Dawn","Noon","Dusk"],"scanClue":"Tap the notch where the two carved rays meet.","scanTarget":{"x":112,"y":378,"radius":32},"rhythmBeats":[900,1800,2700,3600],"physics":{"kind":"mirror","prompt":"Which counterweight pairing turns the mirror toward the Sunstone?","choices":["Heavy left · light right","Light left · heavy right","Both on the left"],"correct":1,"successText":"The mirror catches the final beam. The Sunstone awakens."}}}}'::jsonb),
('week1-day2-airship', 1, 'draft', null, 'Clockwork Airship', 'The Storm Engine', '{"id":"week1-day2-airship","weekIndex":1,"status":"draft","publishDate":null,"title":"Clockwork Airship","subtitle":"The Storm Engine","synopsis":"Board a brass airship and repair its storm engine before the thunderhead swallows Brasshaven.","estimatedMinutes":"6–8 minutes","art":{"key":"airship","background":"backplates/airship.webp","accent":"#e7a84d","accent2":"#5bc0be","ink":"#172b35","paper":"#fff7df","atmosphere":"Brass decks, teal storm clouds, propellers and suspended cargo","artifact":"Storm Cog","motif":"⚙"},"levelOrder":["trivia","logic","spatial","rhythm","finale"],"puzzles":{"trivia":{"type":"trivia","title":"Weather Deck","brief":"Prove you understand the sky before entering the engine room.","questions":[{"prompt":"Which lifting gas is nonflammable and less dense than air?","choices":["Oxygen","Helium","Carbon dioxide","Nitrogen"],"correct":1,"fact":"Helium is light and nonflammable."},{"prompt":"Which instrument measures atmospheric pressure?","choices":["Thermometer","Anemometer","Barometer","Hygrometer"],"correct":2,"fact":"A barometer measures atmospheric pressure."},{"prompt":"Which cloud type most often produces thunderstorms?","choices":["Cirrus","Stratus","Cumulonimbus","Altocumulus"],"correct":2,"fact":"Cumulonimbus clouds can produce thunder, lightning, and heavy rain."}]},"logic":{"type":"logic","title":"Cargo Rail","brief":"Load the four supply crates from bow to stern.","tokens":["Compass","Tools","Water","Fuel"],"clues":[{"text":"The Compass is left of the Tools.","rule":{"kind":"before","left":"Compass","right":"Tools"}},{"text":"Fuel is immediately right of Water.","rule":{"kind":"immediatelyBefore","left":"Water","right":"Fuel"}},{"text":"Tools are not at either end.","rule":{"kind":"notPosition","token":"Tools","indexes":[0,3]}},{"text":"Water is not first.","rule":{"kind":"notPosition","token":"Water","indexes":[0]}}],"solution":["Compass","Tools","Water","Fuel"]},"rhythm":{"type":"rhythm","title":"Twelve-Pin Engine","brief":"Tap as each rotating pin enters the illuminated lock.","actionLabel":"SET PIN","cueLabel":"LOCK","beatMap":[2400,4535,6870,9000,11235,13670,15900,18335,20770,23100,25635,28170],"durationMs":30000,"windowMs":360,"maxErrors":3},"spatial":{"type":"spatial","title":"Storm Deck Release","brief":"Find the emergency pin before lightning reaches the mast.","clue":"Follow the engraved pipe arrows; the last arrow vanishes behind a rope.","targetLabel":"Emergency pin","target":{"x":306,"y":332,"radius":32},"hints":["Trace the brass pipe from the engine.","The pin sits behind the dark foreground rope."],"maxTaps":3},"finale":{"type":"finale","title":"Thunderhead Engine","brief":"Ground the coil, restore cargo order, lock the turbine, and balance the deck.","question":{"prompt":"Which instrument warned the crew that air pressure was falling?","choices":["Compass","Barometer","Clock","Altimeter"],"correct":1,"fact":"A falling barometer can signal an approaching storm."},"orderTokens":["Compass","Tools","Fuel"],"orderSolution":["Compass","Tools","Fuel"],"scanClue":"Tap the grounded coil marked by three descending arrows.","scanTarget":{"x":302,"y":380,"radius":30},"rhythmBeats":[850,1700,2600,3500],"physics":{"kind":"ballast","prompt":"The bow is rising too high. Where should the two ballast bags go?","choices":["Both at the bow","One at each end","Both at the stern"],"correct":0,"successText":"The bow settles, the propellers bite, and the airship climbs."}}}}'::jsonb),
('week1-day3-library', 2, 'draft', null, 'Sunken Library', 'The Drowned Index', '{"id":"week1-day3-library","weekIndex":2,"status":"draft","publishDate":null,"title":"Sunken Library","subtitle":"The Drowned Index","synopsis":"Descend through a drowned archive where living lights guard a map no surface explorer has seen.","estimatedMinutes":"6–8 minutes","art":{"key":"library","background":"backplates/library.webp","accent":"#4ecdc4","accent2":"#9676d9","ink":"#102a36","paper":"#effdfa","atmosphere":"Submerged shelves, turquoise shafts, violet jellyfish and drifting pages","artifact":"Tide Index","motif":"◈"},"levelOrder":["spatial","trivia","logic","rhythm","finale"],"puzzles":{"trivia":{"type":"trivia","title":"Abyssal Catalogue","brief":"Answer three questions before the ink dissolves.","questions":[{"prompt":"Which trench contains the deepest known point in Earth’s oceans?","choices":["Java Trench","Puerto Rico Trench","Mariana Trench","Tonga Trench"],"correct":2,"fact":"Challenger Deep lies in the Mariana Trench."},{"prompt":"What is light produced by a living organism called?","choices":["Fluorescence","Bioluminescence","Refraction","Phosphorescence"],"correct":1,"fact":"Bioluminescence is light made by a living organism."},{"prompt":"Which upward force helps objects float in water?","choices":["Friction","Gravity","Buoyancy","Magnetism"],"correct":2,"fact":"Buoyancy is the upward force exerted by a fluid."}]},"logic":{"type":"logic","title":"Floodgate Shelves","brief":"Place the four archive seals from left to right.","tokens":["Pearl","Ink","Coral","Key"],"clues":[{"text":"Ink is immediately left of Key.","rule":{"kind":"immediatelyBefore","left":"Ink","right":"Key"}},{"text":"Pearl is right of Key.","rule":{"kind":"before","left":"Key","right":"Pearl"}},{"text":"Coral is at the left end.","rule":{"kind":"position","token":"Coral","index":0}}],"solution":["Coral","Ink","Key","Pearl"]},"rhythm":{"type":"rhythm","title":"Pressure Rings","brief":"Ping the bathysphere through twelve closing sonar rings.","actionLabel":"PING","cueLabel":"ECHO","beatMap":[2400,4520,6840,9000,11220,13640,15900,18320,20740,23100,25620,28140],"durationMs":30000,"windowMs":360,"maxErrors":3},"spatial":{"type":"spatial","title":"Mural of Tides","brief":"Find the shell key hidden in the flooded mosaic.","clue":"Two trails of bubbles meet where the missing shell belongs.","targetLabel":"Shell key","target":{"x":118,"y":390,"radius":35},"hints":["Ignore the painted fish.","Look where both bubble trails end."],"maxTaps":3},"finale":{"type":"finale","title":"Leviathan Archive","brief":"Read the depth clue, restore the index, open the valve, and raise the final shelf.","question":{"prompt":"Which force can raise the drowned shelf?","choices":["Buoyancy","Friction","Gravity","Static charge"],"correct":0,"fact":"Air-filled bladders increase buoyancy."},"orderTokens":["Coral","Ink","Key"],"orderSolution":["Coral","Ink","Key"],"scanClue":"Tap the valve between the converging bubbles.","scanTarget":{"x":276,"y":346,"radius":30},"rhythmBeats":[900,1650,2550,3450],"physics":{"kind":"buoyancy","prompt":"Where should the two air bladders attach to lift the shelf level?","choices":["Both in the center","One at each outer end","Both on the left"],"correct":1,"successText":"The shelf rises level and becomes a bridge to the Tide Index."}}}}'::jsonb),
('week1-day4-forest', 3, 'draft', null, 'Moonlit Forest', 'The Lantern Stag', '{"id":"week1-day4-forest","weekIndex":3,"status":"draft","publishDate":null,"title":"Moonlit Forest","subtitle":"The Lantern Stag","synopsis":"Follow a crown of fireflies into a silver forest and return the Moon Lantern to its guardian.","estimatedMinutes":"6–8 minutes","art":{"key":"forest","background":"backplates/forest.webp","accent":"#80d6a3","accent2":"#d8b4fe","ink":"#152b2b","paper":"#f7fff5","atmosphere":"Layered moonlit trees, luminous moss, fireflies and antler silhouettes","artifact":"Moon Lantern","motif":"☾"},"levelOrder":["rhythm","logic","spatial","trivia","finale"],"puzzles":{"trivia":{"type":"trivia","title":"Naturalist’s Hollow","brief":"Name the living patterns that guide travelers after dark.","questions":[{"prompt":"What mainly causes the Moon’s phases?","choices":["Earth’s shadow every night","Changing views of its sunlit half","Clouds crossing its surface","The Moon producing less light"],"correct":1,"fact":"Moon phases come from our changing view of the Moon’s sunlit half."},{"prompt":"Lichen commonly combines a fungus with which partner?","choices":["An insect","An alga or cyanobacterium","A moss root","A fern"],"correct":1,"fact":"Lichen is a partnership between a fungus and a photosynthetic organism."},{"prompt":"An animal that is active mainly at night is called what?","choices":["Diurnal","Nocturnal","Aquatic","Migratory"],"correct":1,"fact":"Nocturnal animals are primarily active at night."}]},"logic":{"type":"logic","title":"Procession of Tracks","brief":"Place the four forest signs in their trail order.","tokens":["Moth","Owl","Fox","Stag"],"clues":[{"text":"Moth is immediately left of Owl.","rule":{"kind":"immediatelyBefore","left":"Moth","right":"Owl"}},{"text":"Fox is right of Owl.","rule":{"kind":"before","left":"Owl","right":"Fox"}},{"text":"Stag is at the right end.","rule":{"kind":"position","token":"Stag","index":3}}],"solution":["Moth","Owl","Fox","Stag"]},"rhythm":{"type":"rhythm","title":"Firefly Crossing","brief":"Tap with each bright swarm to vault the roots below.","actionLabel":"FOLLOW","cueLabel":"GLOW","beatMap":[2400,4545,6890,9000,11245,13690,15900,18345,20790,23100,25645,28190],"durationMs":30000,"windowMs":360,"maxErrors":3},"spatial":{"type":"spatial","title":"The Listening Oak","brief":"Find the antler-shaped release hidden in the bark.","clue":"The moonbeam points to a hollow shaped like half a crown.","targetLabel":"Antler notch","target":{"x":284,"y":350,"radius":34},"hints":["Follow the pale moonbeam.","The notch is on the right side of the hollow."],"maxTaps":3},"finale":{"type":"finale","title":"Hollow Oak Guardian","brief":"Read the moon, follow the tracks, find the hinge, and balance the lantern bridge.","question":{"prompt":"Why does the Moon appear to change shape?","choices":["Clouds cover it","We see different portions of its sunlit half","It shrinks each month","Earth blocks it nightly"],"correct":1,"fact":"The Moon’s phases are changing views of its illuminated half."},"orderTokens":["Moth","Owl","Stag"],"orderSolution":["Moth","Owl","Stag"],"scanClue":"Tap the hinge inside the crescent-shaped knot.","scanTarget":{"x":110,"y":362,"radius":30},"rhythmBeats":[800,1600,2450,3350],"physics":{"kind":"balance","prompt":"How can a heavy lantern balance a light one across the branch?","choices":["Heavy near pivot · light far away","Both at the far end","Light near pivot · heavy far away"],"correct":0,"successText":"The torques balance. The branch lowers into a moonlit bridge."}}}}'::jsonb),
('week1-day5-observatory', 4, 'draft', null, 'Polar Observatory', 'The Aurora Signal', '{"id":"week1-day5-observatory","weekIndex":4,"status":"draft","publishDate":null,"title":"Polar Observatory","subtitle":"The Aurora Signal","synopsis":"Wake an icebound observatory and send one last signal through a sky alive with color.","estimatedMinutes":"6–8 minutes","art":{"key":"observatory","background":"backplates/observatory.webp","accent":"#66e0cf","accent2":"#7c8cff","ink":"#15283b","paper":"#f1fbff","atmosphere":"Snow shelves, glass domes, aurora ribbons and crystalline radio towers","artifact":"Aurora Lens","motif":"✦"},"levelOrder":["trivia","spatial","rhythm","logic","finale"],"puzzles":{"trivia":{"type":"trivia","title":"Field Notes in Ice","brief":"Answer before the frost covers the observatory glass.","questions":[{"prompt":"Auroras begin when charged particles primarily arrive from where?","choices":["The Moon","The Sun","The oceans","Volcanoes"],"correct":1,"fact":"Charged particles from the Sun interact with gases in Earth’s upper atmosphere."},{"prompt":"Which star is commonly used to locate north in the Northern Hemisphere?","choices":["Sirius","Betelgeuse","Polaris","Vega"],"correct":2,"fact":"Polaris lies close to the north celestial pole."},{"prompt":"At which temperature do Celsius and Fahrenheit have the same numerical value?","choices":["−40°","0°","32°","100°"],"correct":0,"fact":"−40 degrees is the same on both scales."}]},"logic":{"type":"logic","title":"Signal Prisms","brief":"Align the four observatory symbols.","tokens":["Comet","Aurora","Moon","Star"],"clues":[{"text":"Aurora is immediately left of Moon.","rule":{"kind":"immediatelyBefore","left":"Aurora","right":"Moon"}},{"text":"Comet is left of Aurora.","rule":{"kind":"before","left":"Comet","right":"Aurora"}},{"text":"Star is right of Moon.","rule":{"kind":"before","left":"Moon","right":"Star"}}],"solution":["Comet","Aurora","Moon","Star"]},"rhythm":{"type":"rhythm","title":"Aurora Telegraph","brief":"Key twelve pulses as the ribbons cross the antenna.","actionLabel":"TRANSMIT","cueLabel":"SIGNAL","beatMap":[2400,4525,6850,9000,11225,13650,15900,18325,20750,23100,25625,28150],"durationMs":30000,"windowMs":360,"maxErrors":3},"spatial":{"type":"spatial","title":"Frozen Breaker Panel","brief":"Find the breaker concealed beneath the frost.","clue":"Two constellation lines intersect at the only star with six points.","targetLabel":"Ice breaker","target":{"x":126,"y":336,"radius":35},"hints":["Trace both etched constellations.","Tap the six-pointed intersection."],"maxTaps":3},"finale":{"type":"finale","title":"Whiteout Dish","brief":"Read the aurora, align the prisms, uncover the pivot, and turn the dish into the wind.","question":{"prompt":"Which star marks north for this observatory?","choices":["Polaris","Sirius","Vega","Rigel"],"correct":0,"fact":"Polaris is the traditional Northern Hemisphere guide star."},"orderTokens":["Comet","Aurora","Star"],"orderSolution":["Comet","Aurora","Star"],"scanClue":"Tap the pivot under the six-pointed frost mark.","scanTarget":{"x":294,"y":354,"radius":30},"rhythmBeats":[850,1750,2600,3500],"physics":{"kind":"dish","prompt":"A strong wind pushes the dish right. Where should the ice counterweight go?","choices":["Rightmost socket","Center socket","Leftmost socket"],"correct":2,"successText":"The counterweight holds. The dish locks onto the Aurora Signal."}}}}'::jsonb),
('week1-day6-caravan', 5, 'draft', null, 'Desert Caravan', 'The Glass Compass', '{"id":"week1-day6-caravan","weekIndex":5,"status":"draft","publishDate":null,"title":"Desert Caravan","subtitle":"The Glass Compass","synopsis":"Cross a field of mirages and align an ancient caravan gate before the last shadow disappears.","estimatedMinutes":"6–8 minutes","art":{"key":"caravan","background":"backplates/caravan.webp","accent":"#f1b45a","accent2":"#e87955","ink":"#36291f","paper":"#fff7e8","atmosphere":"Layered dunes, canvas caravans, long shadows and glass obelisks","artifact":"Glass Compass","motif":"◇"},"levelOrder":["logic","trivia","rhythm","spatial","finale"],"puzzles":{"trivia":{"type":"trivia","title":"Wayfinder’s Questions","brief":"Separate desert knowledge from convincing mirages.","questions":[{"prompt":"A common road mirage is mainly caused by what?","choices":["Reflection from sand grains","Refraction through layers of warm air","Magnetism","Moonlight"],"correct":1,"fact":"Temperature layers bend light through refraction."},{"prompt":"What do camel humps primarily store?","choices":["Water","Fat","Air","Salt"],"correct":1,"fact":"Camel humps store fat that can be metabolized for energy."},{"prompt":"Where do all lines of longitude meet?","choices":["At the equator","At the poles","At the tropics","At sea level"],"correct":1,"fact":"Meridians converge at the North and South Poles."}]},"logic":{"type":"logic","title":"Caravan Order","brief":"Arrange the caravan from front scout to rear cargo.","tokens":["Scout","Lantern","Water","Goods"],"clues":[{"text":"Water is immediately before Goods.","rule":{"kind":"immediatelyBefore","left":"Water","right":"Goods"}},{"text":"Scout is before Water.","rule":{"kind":"before","left":"Scout","right":"Water"}},{"text":"Lantern is neither first nor last.","rule":{"kind":"notPosition","token":"Lantern","indexes":[0,3]}}],"solution":["Scout","Lantern","Water","Goods"]},"rhythm":{"type":"rhythm","title":"Dune Runner","brief":"Tap the reins as each safe ridge passes under the lead camel.","actionLabel":"REIN","cueLabel":"RIDE","beatMap":[2400,4530,6860,9000,11230,13660,15900,18330,20760,23100,25630,28160],"durationMs":30000,"windowMs":360,"maxErrors":3},"spatial":{"type":"spatial","title":"The Honest Shadow","brief":"Find the wheel pin whose shadow matches the real sun.","clue":"Mirages point both ways. Only one spoke casts a shadow away from the sun.","targetLabel":"Compass pin","target":{"x":276,"y":386,"radius":34},"hints":["Look at the true sun, not its reflection.","The real pin is on the right wheel."],"maxTaps":3},"finale":{"type":"finale","title":"Sandglass Gate","brief":"Read the mirage, restore the caravan, find the vent, and steer light through the obelisk.","question":{"prompt":"What bends light above the hot road?","choices":["Refraction","Magnetism","Gravity alone","Sound"],"correct":0,"fact":"Refraction through air layers produces the mirage."},"orderTokens":["Scout","Lantern","Water"],"orderSolution":["Scout","Lantern","Water"],"scanClue":"Tap the vent beneath the shadow that points away from the sun.","scanTarget":{"x":114,"y":382,"radius":31},"rhythmBeats":[900,1800,2650,3500],"physics":{"kind":"sandglass","prompt":"Which sand-weight placement tilts the mirror toward the obelisk?","choices":["Full left · half right","Both on the right","Half left · full right"],"correct":0,"successText":"The falling sand turns the mirror and opens the Glass Compass vault."}}}}'::jsonb),
('week1-day7-citadel', 6, 'draft', null, 'Sky Citadel', 'The Last Horizon', '{"id":"week1-day7-citadel","weekIndex":6,"status":"draft","publishDate":null,"title":"Sky Citadel","subtitle":"The Last Horizon","synopsis":"Assemble the Atlas Engine above the clouds and open the trail to every Venture still to come.","estimatedMinutes":"6–8 minutes","art":{"key":"citadel","background":"backplates/citadel.webp","accent":"#7bdff2","accent2":"#f6c85f","ink":"#172b46","paper":"#f5fbff","atmosphere":"Floating stone islands, cloud bridges, banners and a vast brass orrery","artifact":"Atlas Key","motif":"✧"},"levelOrder":["spatial","rhythm","logic","trivia","finale"],"puzzles":{"trivia":{"type":"trivia","title":"Lessons of the Upper Air","brief":"Answer the citadel’s final questions.","questions":[{"prompt":"In which atmospheric layer does most weather occur?","choices":["Stratosphere","Mesosphere","Troposphere","Thermosphere"],"correct":2,"fact":"Most weather occurs in the troposphere."},{"prompt":"Which instrument measures wind speed?","choices":["Barometer","Anemometer","Hygrometer","Altimeter"],"correct":1,"fact":"An anemometer measures wind speed."},{"prompt":"Why do many sunsets appear red or orange?","choices":["Red light travels fastest","Shorter blue wavelengths scatter more","Clouds create red light","The Sun cools down"],"correct":1,"fact":"More blue light scatters out of the long path through the atmosphere."}]},"logic":{"type":"logic","title":"Banners of the Horizon","brief":"Order the four banners along the western parapet.","tokens":["Star","Wave","Sun","Wing"],"clues":[{"text":"Wing is immediately right of Sun.","rule":{"kind":"immediatelyBefore","left":"Sun","right":"Wing"}},{"text":"Wave is not at either end.","rule":{"kind":"notPosition","token":"Wave","indexes":[0,3]}},{"text":"Star is left of Wave.","rule":{"kind":"before","left":"Star","right":"Wave"}}],"solution":["Star","Wave","Sun","Wing"]},"rhythm":{"type":"rhythm","title":"Cloud Gate Glide","brief":"Tap each wind crest to lift the glider through twelve rings.","actionLabel":"FLAP","cueLabel":"LIFT","beatMap":[2400,4540,6880,9000,11240,13680,15900,18340,20780,23100,25640,28180],"durationMs":30000,"windowMs":360,"maxErrors":3},"spatial":{"type":"spatial","title":"Seventh Socket","brief":"Find the final socket in the citadel relief.","clue":"A split pennant hides the star missing from the stone constellation.","targetLabel":"Star socket","target":{"x":300,"y":366,"radius":34},"hints":["Look behind the moving banners.","The split gold pennant covers the socket."],"maxTaps":3},"finale":{"type":"finale","title":"Atlas Engine","brief":"Read the sky, align the banners, uncover the anchor, and balance the final orrery.","question":{"prompt":"Which layer carries the storm around the citadel?","choices":["Troposphere","Exosphere","Mesosphere","Thermosphere"],"correct":0,"fact":"The troposphere contains most of Earth’s weather."},"orderTokens":["Star","Wave","Sun"],"orderSolution":["Star","Wave","Sun"],"scanClue":"Tap the anchor beneath the split pennant.","scanTarget":{"x":104,"y":360,"radius":30},"rhythmBeats":[750,1500,2350,3250],"physics":{"kind":"orrery","prompt":"Which arrangement balances the three relic arms before launch?","choices":["Light · medium · heavy clockwise","Heavy · light · medium clockwise","All relics on one arm"],"correct":1,"successText":"The Atlas Engine balances. The explorer flies through the last horizon."}}}}'::jsonb)
